# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using UnityEngine;

public class PlayerStats : MonoBehaviour
{
    public int health = 100;
    public int maxHealth = 100;
    public float currency = 0f;
    public int armor = 0;
    public float damageMultiplier = 1f;

    void Start()
    {
        health = maxHealth;
    }

    public void TakeDamage(int baseDamage)
    {
        int actualDamage = CalculateDamage(baseDamage);
        health -= actualDamage;
        
        if (health < 0)
        {
            health = 0;
        }
        
        Debug.Log("Player took " + actualDamage + " damage. Health: " + health);
        
        if (health <= 0)
        {
            Die();
        }
    }

    public int CalculateDamage(int baseDamage)
    {
        float damageReduction = armor * 0.5f;
        int finalDamage = Mathf.Max(1, baseDamage - (int)damageReduction);
        return finalDamage;
    }

    public void Heal(int amount)
    {
        health += amount;
        if (health > maxHealth)
        {
            health = maxHealth;
        }
        Debug.Log("Player healed " + amount + ". Health: " + health);
    }

    public void AddCurrency(float amount)
    {
        currency += amount;
        Debug.Log("Currency added: " + amount + ". Total: " + currency);
    }

    public bool SpendCurrency(float amount)
    {
        if (currency >= amount)
        {
            currency -= amount;
            Debug.Log("Currency spent: " + amount + ". Remaining: " + currency);
            return true;
        }
        Debug.Log("Not enough currency!");
        return false;
    }

    void Die()
    {
        Debug.Log("Player died!");
    }
}

public class Enemy : MonoBehaviour
{
    public int health = 50;
    public int baseDamage = 10;
    
    PlayerStats playerStats;

    void Start()
    {
        playerStats = FindObjectOfType<PlayerStats>();
    }

    public void TakeDamage(int damage)
    {
        int calculatedDamage = CalculatePlayerDamage(damage);
        health -= calculatedDamage;
        
        Debug.Log("Enemy took " + calculatedDamage + " damage. Health: " + health);
        
        if (health <= 0)
        {
            Die();
        }
    }

    public int CalculatePlayerDamage(int baseDamage)
    {
        if (playerStats != null)
        {
            return (int)(baseDamage * playerStats.damageMultiplier);
        }
        return baseDamage;
    }

    public void AttackPlayer()
    {
        if (playerStats != null)
        {
            playerStats.TakeDamage(baseDamage);
        }
    }

    void Die()
    {
        Debug.Log("Enemy died!");
        if (playerStats != null)
        {
            playerStats.AddCurrency(10f);
        }
        Destroy(gameObject);
    }
}

public class ShopItem
{
    public string itemName;
    public float basePrice;
    public int purchaseCount;
    
    public ShopItem(string name, float price)
    {
        itemName = name;
        basePrice = price;
        purchaseCount = 0;
    }
    
    public float GetCurrentPrice()
    {
        return basePrice * (1 + purchaseCount * 0.5f);
    }
}

public class Shop : MonoBehaviour
{
    public ShopItem healthPotion;
    public ShopItem armorUpgrade;
    public ShopItem damageUpgrade;
    public ShopItem maxHealthUpgrade;
    
    PlayerStats playerStats;

    void Start()
    {
        playerStats = FindObjectOfType<PlayerStats>();
        
        healthPotion = new ShopItem("Health Potion", 10f);
        armorUpgrade = new ShopItem("Armor Upgrade", 50f);
        damageUpgrade = new ShopItem("Damage Upgrade", 75f);
        maxHealthUpgrade = new ShopItem("Max Health Upgrade", 100f);
    }

    public bool PurchaseHealthPotion()
    {
        float price = healthPotion.GetCurrentPrice();
        
        if (playerStats.SpendCurrency(price))
        {
            healthPotion.purchaseCount++;
            playerStats.Heal(50);
            Debug.Log("Purchased Health Potion for " + price);
            return true;
        }
        return false;
    }

    public bool PurchaseArmorUpgrade()
    {
        float price = armorUpgrade.GetCurrentPrice();
        
        if (playerStats.SpendCurrency(price))
        {
            armorUpgrade.purchaseCount++;
            playerStats.armor += 5;
            Debug.Log("Purchased Armor Upgrade for " + price + ". Armor: " + playerStats.armor);
            return true;
        }
        return false;
    }

    public bool PurchaseDamageUpgrade()
    {
        float price = damageUpgrade.GetCurrentPrice();
        
        if (playerStats.SpendCurrency(price))
        {
            damageUpgrade.purchaseCount++;
            playerStats.damageMultiplier += 0.25f;
            Debug.Log("Purchased Damage Upgrade for " + price + ". Multiplier: " + playerStats.damageMultiplier);
            return true;
        }
        return false;
    }

    public bool PurchaseMaxHealthUpgrade()
    {
        float price = maxHealthUpgrade.GetCurrentPrice();
        
        if (playerStats.SpendCurrency(price))
        {
            maxHealthUpgrade.purchaseCount++;
            playerStats.maxHealth += 20;
            playerStats.health += 20;
            Debug.Log("Purchased Max Health Upgrade for " + price + ". Max Health: " + playerStats.maxHealth);
            return true;
        }
        return false;
    }

    public float GetHealthPotionPrice()
    {
        return healthPotion.GetCurrentPrice();
    }

    public float GetArmorUpgradePrice()
    {
        return armorUpgrade.GetCurrentPrice();
    }

    public float GetDamageUpgradePrice()
    {
        return damageUpgrade.GetCurrentPrice();
    }

    public float GetMaxHealthUpgradePrice()
    {
        return maxHealthUpgrade.GetCurrentPrice();
    }
}

public class CombatSystem : MonoBehaviour
{
    PlayerStats playerStats;
    
    void Start()
    {
        playerStats = FindObjectOfType<PlayerStats>();
    }

    public void PlayerAttackEnemy(Enemy enemy, int baseDamage)
    {
        if (enemy != null)
        {
            enemy.TakeDamage(baseDamage);
        }
    }

    public int CalculateCriticalHit(int baseDamage, float critChance, float critMultiplier)
    {
        if (Random.value < critChance)
        {
            return (int)(baseDamage * critMultiplier);
        }
        return baseDamage;
    }
}

public class GameManager : MonoBehaviour
{
    public PlayerStats playerStats;
    public Shop shop;
    public CombatSystem combatSystem;

    void Start()
    {
        if (playerStats == null)
            playerStats = FindObjectOfType<PlayerStats>();
        if (shop == null)
            shop = FindObjectOfType<Shop>();
        if (combatSystem == null)
            combatSystem = FindObjectOfType<CombatSystem>();
    }

    public void SavePlayerData()
    {
        PlayerPrefs.SetInt("PlayerHealth", playerStats.health);
        PlayerPrefs.SetInt("PlayerMaxHealth", playerStats.maxHealth);
        PlayerPrefs.SetFloat("PlayerCurrency", playerStats.currency);
        PlayerPrefs.SetInt("PlayerArmor", playerStats.armor);
        PlayerPrefs.SetFloat("PlayerDamageMultiplier", playerStats.damageMultiplier);
        PlayerPrefs.Save();
    }

    public void LoadPlayerData()
    {
        playerStats.health = PlayerPrefs.GetInt("PlayerHealth", 100);
        playerStats.maxHealth = PlayerPrefs.GetInt("PlayerMaxHealth", 100);
        playerStats.currency = PlayerPrefs.GetFloat("PlayerCurrency", 0f);
        playerStats.armor = PlayerPrefs.GetInt("PlayerArmor", 0);
        playerStats.damageMultiplier = PlayerPrefs.GetFloat("PlayerDamageMultiplier", 1f);
    }
}